class Node:
 def __init__(self, data):
 self.data = data
 self.left = None
 self.right = None

class ExpressionTree:
 def __init__(self):
 self.root = None
 def evaluate(self, node):
 if node is None:
 return 0
 if node.left is None and node.right is None:
 return node.data
 left_result = self.evaluate(node.left)
 right_result = self.evaluate(node.right)
 if node.data == '+':
 return left_result + right_result
 elif node.data == '-':
 return left_result - right_result
 elif node.data == '*':
 return left_result * right_result
 elif node.data == '/':
 return left_result / right_result

typedef struct Node {
 char data;
 float value;
 struct Node* left;
 struct Node* right;
} Node;

Node* create_node(char data) {
 Node* newNode = (Node*)malloc(sizeof(Node));
 newNode->data = data;
 newNode->left = newNode->right = NULL;
 return newNode;
}

float evaluate(Node* root) {
 if (root == NULL)
 return 0;
 if (root->left == NULL && root->right == NULL)
 return root->value;
 float left_val = evaluate(root->left);
 float right_val = evaluate(root->right);
 switch (root->data) {
 case '+':
 return left_val + right_val;
 case '-':
 return left_val - right_val;
 case '*':
 return left_val * right_val;
 case '/':
 return left_val / right_val;
 default:
 return 0;
 }
}
